static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dReluHardSwishCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0); // N, C_in, H, W
    const gert::Shape *w_shape = context->GetInputShape(1); // C_out, C_in, K, K

    if (x_shape->GetDimNum() < 4 || w_shape->GetDimNum() < 4) {
        return ge::GRAPH_FAILED;
    }

    const int64_t N = x_shape->GetDim(0);
    const int64_t Cin = x_shape->GetDim(1);
    const int64_t H = x_shape->GetDim(2);
    const int64_t W = x_shape->GetDim(3);

    const int64_t Cout = w_shape->GetDim(0);
    const int64_t Cin_w = w_shape->GetDim(1);
    const int64_t K_h = w_shape->GetDim(2);
    const int64_t K_w = w_shape->GetDim(3);

    if (Cin != Cin_w || K_h != K_w) {
        return ge::GRAPH_FAILED;
    }

    const int64_t K = K_h;
    // Fixed stride=1, pad=0, dil=1
    const int64_t HOut = H - K + 1;
    const int64_t WOut = W - K + 1;

    if (HOut <= 0 || WOut <= 0) {
        return ge::GRAPH_FAILED;
    }

    const uint64_t totalOut = static_cast<uint64_t>(N) * static_cast<uint64_t>(Cout) *
                              static_cast<uint64_t>(HOut) * static_cast<uint64_t>(WOut);

    // BlockDim heuristic: number of SMs
    uint32_t blockDim = 24;
    if (totalOut < 24ULL) {
        blockDim = static_cast<uint32_t>(totalOut);
        if (blockDim == 0) blockDim = 1;
    }
    context->SetBlockDim(blockDim);

    // hasBias flag
    uint32_t hasBias = (context->GetInputShape(2) != nullptr && context->GetInputShape(2)->GetShapeSize() > 0) ? 1u : 0u;

    tiling.set_N(static_cast<uint32_t>(N));
    tiling.set_Cin(static_cast<uint32_t>(Cin));
    tiling.set_Cout(static_cast<uint32_t>(Cout));
    tiling.set_H(static_cast<uint32_t>(H));
    tiling.set_W(static_cast<uint32_t>(W));
    tiling.set_K(static_cast<uint32_t>(K));
    tiling.set_HOut(static_cast<uint32_t>(HOut));
    tiling.set_WOut(static_cast<uint32_t>(WOut));
    tiling.set_totalOut(totalOut);
    tiling.set_blockDim(blockDim);
    tiling.set_hasBias(hasBias);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

