                                           const at::Tensor& weight,
                                           c10::optional<at::Tensor> bias_opt) {
    // Output shape inferred on host by framework; here we only allocate empty_like with conv inference
    // For simplicity, defer shape inference to NPU runtime; allocate result with same dtype/device.
    at::Tensor result;
    if (bias_opt.has_value()) {
        result = at::empty({}, x.options()); // NPU runtime will resize
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, bias_opt.value(), result);
    } else {
        at::Tensor undef_bias;
        result = at::empty({}, x.options());
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, undef_bias, result);
    }
    return result;
}

